"""Gradio app for preference voting
Author: linjunyao
"""

# Import necessary libraries
import argparse
import json
import os
from pathlib import Path

import gradio as gr
from loguru import logger

# Example conversations stored as a Python list of dictionaries
EXAMPLE_CONVERSATIONS = [
    {
        "conversation_id": 1,
        "instruction": "Hello, how are you?",
        "category": "chat",
    },
    {
        "conversation_id": 2,
        "instruction": "What is the capital of France?",
        "category": "domain_knowledge",
    },
    {
        "conversation_id": 3,
        "instruction": "Tell me a joke.",
        "category": "chat",
    },
    {
        "conversation_id": 4,
        "instruction": "write a python function for the Fibinacci sequence.",
        "category": "code",
    },
]


def get_conversations(_file_path_):
    if isinstance(file_path, str):
        file_path = Path(file_path)

    conversations = []

    if file_path.exists():
        if file_path.suffix.lower() == ".json":
            with open(file_path, _mode_="r") as infile:
                conversations = json.load(infile)
        elif file_path.suffix.lower() == ".jsonl":
            with open(file_path, _mode_="r") as infile:
                for line in infile:
                    conversations.append(json.loads(line.strip()))
        else:
            raise ValueError(
                "Unsupported file format. Please provide a JSON or JSONL file."
            )
    else:
        conversations = (
            EXAMPLE_CONVERSATIONS  # Assuming EXAMPLE_CONVERSATIONS is defined elsewhere
        )

    return conversations


def convert_singleturn_convo(
    _input_dict_: dict,
    _question_key_: str = "question",
    _answer_key_: str = "answer",
) -> list[dict]:
    output_list = [
        {
            "role": "user",
            "content": input_dict[question_key]["content"],
        }
    ]

    if answer_key in input_dict:
        output_list.append(
            {
                "role": "assistant",
                "content": input_dict[answer_key]["content"],
            },
        )

    return output_list


# Helper function to load existing conversation IDs from a JSON or JSONL file
def load_voted_conversation_ids(_file_path_):
    if isinstance(file_path, str):
        file_path = Path(file_path)

    convo_id_name = args.conversation_id_name

    voted_ids = set()
    if not file_path.exists():
        return voted_ids

    if str(file_path).endswith(".jsonl"):
        # Read JSONL file line by line
        with open(file_path, "r") as file:
            for line in file:
                try:
                    data = json.loads(line)
                    if convo_id_name in data:
                        voted_ids.add(data[convo_id_name])
                except json.JSONDecodeError:
                    continue

    elif str(file_path).endswith(".json"):
        # Read JSON file
        with open(file_path, "r") as file:
            try:
                data = json.load(file)
                if isinstance(data, list):
                    for item in data:
                        if convo_id_name in item:
                            voted_ids.add(item[convo_id_name])
            except json.JSONDecodeError:
                pass

    return voted_ids


# Function to get the next conversation pair, skipping already-voted conversations
def get_next_conversation(_conversations_, _current_conversation_index_, _voted_ids_):
    convo_id_name = args.conversation_id_name

    while current_conversation_index < len(conversations):
        conversation = conversations[current_conversation_index]
        current_conversation_index += 1

        if not args.latest:
            return conversation, current_conversation_index

        # Skip conversations that already have a vote
        if conversation[convo_id_name] not in voted_ids:
            logger.debug(f"{conversation[convo_id_name]}")
            logger.debug(f"{voted_ids}")
            return conversation, current_conversation_index

    return None, current_conversation_index


# Function to handle the vote and record it
def handle_vote(_vote_, _conversations_, _current_conversation_index_, _voted_ids_):
    convo_id_name = args.conversation_id_name

    current_conversation = conversations[current_conversation_index - 1]

    # Handle non-skip votes
    if vote in ["left", "right", "tie", "flag"]:
        gr.Info("Vote recorded", _duration_=5)

        # Add the internal vote to the current conversation
        current_conversation_with_vote = {**current_conversation, "recorded_vote": vote}

        # Save the conversation with the vote to a file
        with open(args.output_file, "a") as file:
            file.write(
                json.dumps(current_conversation_with_vote, _ensure_ascii_=False) + "\n"
            )

        if args.latest:
            # Add the conversation_id to the voted_ids set
            voted_ids.add(current_conversation[convo_id_name])

    # Fetch the next conversation, regardless of vote type
    conversation, current_conversation_index = get_next_conversation(
        conversations, current_conversation_index, voted_ids
    )
    return conversation, current_conversation_index, voted_ids


# Function to update the chatbots with the next conversation
def update_chatbots(
    _conversation_,
    _question_key_: str = "question",
    _answer_key_: str = "answer",
    _conversation_keys_: list[str] = None,
):
    if conversation is not None:
        if conversation_keys is None:
            convo = convert_singleturn_convo(
                conversation,
                _question_key_=question_key,
                _answer_key_=answer_key,
            )
            return convo
        elif len(conversation_keys) == 1:
            convo = conversation[conversation_keys[0]]

            if isinstance(convo, dict):
                convo = convert_singleturn_convo(
                    _input_dict_=convo,
                    _question_key_=question_key,
                    _answer_key_=answer_key,
                )
                return convo

        convo_a = conversation[conversation_keys[0]]
        convo_b = conversation[conversation_keys[1]]

        if isinstance(convo_a, dict):
            convo_a = convert_singleturn_convo(
                _input_dict_=convo_a,
                _question_key_=question_key,
                _answer_key_=answer_key,
            )
            convo_b = convert_singleturn_convo(
                _input_dict_=convo_b,
                _question_key_=question_key,
                _answer_key_=answer_key,
            )

        chatbot_left_content = convo_a
        chatbot_right_content = convo_b
        return chatbot_left_content, chatbot_right_content
    else:
        gr.Info("No more conversations to vote")

        if len(conversation_keys) < 2:
            return None

        return None, None


# Function to handle left button click
def on_left_click(_conversations_, _current_conversation_index_, _voted_ids_):
    conversation, current_conversation_index, voted_ids = handle_vote(
        "left", conversations, current_conversation_index, voted_ids
    )
    chatbot_left_content, chatbot_right_content = update_chatbots(
        conversation,
        _conversation_keys_=["conversation_a", "conversation_b"],
    )

