        return gr.skip()
    return (
        current_conversation_index,
        chatbot_left_content,
        chatbot_right_content,
        voted_ids,
    )


# Function to handle skip button click
def on_skip_click(_conversations_, _current_conversation_index_, _voted_ids_):
    # Skip the conversation without writing to file or updating voted_ids
    conversation, current_conversation_index = get_next_conversation(
        conversations, current_conversation_index, voted_ids
    )

    gr.Info("Conversation skipped. reload app to see it again.", _duration_=5)

    chatbot_left_content, chatbot_right_content = update_chatbots(
        conversation,
        _conversation_keys_=["conversation_a", "conversation_b"],
    )

    if chatbot_left_content is None:
        return gr.skip()
    return (
        current_conversation_index,
        chatbot_left_content,
        chatbot_right_content,
        voted_ids,
    )


# Function to handle the app's load event
